				try {
					parsed = JSON.parse(error.body) as ParsePreviewErrorResponse;
				} catch {
					parsed = null;
				}
				if (parsed && typeof parsed.code === 'string' && typeof parsed.message === 'string') {
					throw new PreviewApiError(error.status, parsed);
				}
			}
			throw error;
		}
	});
}

