+        sort: map_sort_order(query.sort.as_deref()),
+        time_range: map_time_range(query.time_range.as_deref()),
+        limit: Some(per_page),
+        offset: Some(offset),
+        ..Default::default()
+    };
+
+    (filter, page, per_page, search_mode)
